// Extract data from webhook payload
const payload = $input.all()[0].json;

const subject = payload.subject || 'New Subject';
const filename = payload.filename || 'syllabus.pdf';
const professorName = payload.professor_name || 'Your Professor';

// Build email HTML
let html = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">';
html += '<div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px; text-align: center; border-radius: 10px 10px 0 0;">';
html += '<h1 style="margin: 0;">📚 New Study Material Available!</h1>';
html += '</div>';

html += '<div style="background: #f9f9f9; padding: 30px; border-radius: 0 0 10px 10px;">';
html += `<h2 style="color: #333; margin-top: 0;">New Syllabus: ${subject}</h2>`;
html += `<p style="font-size: 16px; color: #666;">Professor <strong>${professorName}</strong> has uploaded the syllabus for <strong>${subject}</strong>.</p>`;

html += '<div style="background: white; padding: 20px; border-left: 4px solid #667eea; margin: 20px 0; border-radius: 5px;">';
html += '<p style="margin: 0; color: #333;">📄 <strong>File:</strong> ' + filename + '</p>';
html += '</div>';

html += '<p style="color: #333;">You can now ask AI doubts about this subject!</p>';

html += '<div style="text-align: center; margin: 30px 0;">';
html += `<a href="${$env.FRONTEND_URL}/student/chat" style="display: inline-block; background: #667eea; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; font-weight: bold;">Start Asking Doubts →</a>`;
html += '</div>';

html += '<p style="color: #666; font-size: 14px;">The AI is now trained on this material and ready to help you learn!</p>';
html += '</div>';

html += '<div style="text-align: center; margin-top: 20px; color: #999; font-size: 12px;">';
html += '<p>~ The DoubtMap Team</p>';
html += '</div>';
html += '</div>';

return [{
  json: {
    emailBody: html,
    subject: subject,
    professor_name: professorName,
    student_emails: 'students@example.com' // TODO: Get from backend or environment
  }
}];
